module top_module(
	intrIn, intr,
	ack, clk, rst
);input intrIn;
	output intr;
	input ack;
	input clk, rst;

	reg no_intr;

	always @(posedge clk) begin
		if (rst) begin
			no_intr <= 1'b0;
		end
		else if (ack) begin
			no_intr <= 1'b0;
		end
		else begin
			no_intr <= no_intr | intrIn;
		end
	end 

	assign intr = no_intr;endmodule
